import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, Package, X, Save, 
  Loader2, Search, CheckCircle2, Box, Layers, Send, Weight, Clock
} from 'lucide-react';
import GestionInventario from './GestionInventario'; 
import { generarNombreImagen } from '../utils/helpers';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [showManual, setShowManual] = useState(false);
  const [editandoProd, setEditandoProd] = useState(null); // Producto seleccionado para editar
  const [fechasPublicacion, setFechasPublicacion] = useState({ inicio: '', fin: '' });
  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', peso: ''
  });

  const cargarOfertas = useCallback(async () => {
    if (!localId) return;
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  }, [localId, API_URL]);

  useEffect(() => { cargarOfertas(); }, [cargarOfertas]);

  const handleActualizar = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${API_URL}/api/ofertas/${editandoProd._id}`, editandoProd);
      setEditandoProd(null);
      cargarOfertas();
    } catch (err) { alert("Error al actualizar"); }
  };

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`.trim(),
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId,
        precioNuevo: Number(nuevoProd.precioNuevo),
        precioViejo: Number(nuevoProd.precioViejo) || Number(nuevoProd.precioNuevo),
        stock: Number(nuevoProd.stock) || 0,
        peso: Number(nuevoProd.peso) || 0
      };
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      cargarOfertas();
    } catch (err) { alert("Error al guardar"); }
  };

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => o.producto.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [ofertas, searchTerm]);

  return (
    <div style={styles.container}>
      <div style={styles.topBar}>
        <button onClick={() => navigate('/dashboard')} style={styles.btnBack}><ArrowLeft size={18}/> Dashboard</button>
        <div style={styles.badgeLocal}>ID Local: {localId?.slice(-6)}</div>
      </div>

      <div style={styles.header}>
        <h1 style={styles.title}>Panel de Inventario</h1>
        <button onClick={() => setShowManual(true)} style={styles.btnPlus}><Plus size={20}/> Nuevo Manual</button>
      </div>

      <GestionInventario localId={localId} onComplete={cargarOfertas} />

      <div style={styles.searchBox}>
        <Search size={20} color="#94a3b8" />
        <input style={styles.searchInput} placeholder="Buscar productos..." onChange={e => setSearchTerm(e.target.value)} />
      </div>

      <div style={styles.grid}>
        {loading ? <Loader2 className="animate-spin" /> : ofertasFiltradas.map(o => (
          <div key={o._id} style={{...styles.card, border: o.publicado ? '1px solid #d1fae5' : '1px solid #f1f5f9'}}>
            <div style={styles.cardHeader}>
              <span style={o.publicado ? styles.statusPub : styles.statusDraft}>{o.publicado ? 'ONLINE' : 'BORRADOR'}</span>
              <span style={{fontSize:'0.7rem', color: o.peso > 15 ? 'red' : '#64748b'}}>
                <Weight size={12} /> {o.peso}kg
              </span>
            </div>
            <h4 style={styles.prodName}>{o.producto}</h4>
            <div style={styles.priceRow}>
               <span style={styles.price}>${o.precioNuevo}</span>
               <span style={styles.stock}>Stock: {o.stock}</span>
            </div>
            <div style={styles.footer}>
              <button style={styles.btnEdit} onClick={() => setEditandoProd(o)}><Edit size={14}/> Editar</button>
              <button style={styles.btnDel} onClick={async () => {
                 if(window.confirm("¿Eliminar?")) { await axios.delete(`${API_URL}/api/ofertas/${o._id}`); cargarOfertas(); }
              }}><Trash2 size={14}/></button>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL DE EDICIÓN */}
      {editandoProd && (
        <div style={styles.modalOverlay}>
          <div style={styles.modalContent}>
            <div style={styles.modalHeader}>
              <h3>Editar Producto</h3>
              <button onClick={() => setEditandoProd(null)}><X/></button>
            </div>
            <form onSubmit={handleActualizar} style={styles.form}>
              <input style={styles.inputS} value={editandoProd.producto} onChange={e => setEditandoProd({...editandoProd, producto: e.target.value})} placeholder="Nombre" />
              <div style={styles.inputRow}>
                <input style={styles.inputS} type="number" value={editandoProd.precioNuevo} onChange={e => setEditandoProd({...editandoProd, precioNuevo: e.target.value})} placeholder="Precio" />
                <input style={styles.inputS} type="number" value={editandoProd.peso} onChange={e => setEditandoProd({...editandoProd, peso: e.target.value})} placeholder="Peso Kg" />
              </div>
              <button type="submit" style={styles.btnSave}>Guardar Cambios</button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL MANUAL */}
      {showManual && (
        <div style={styles.modalOverlay}>
          <div style={styles.modalContent}>
            <div style={styles.modalHeader}><h3>Nuevo Producto</h3><button onClick={() => setShowManual(false)}><X/></button></div>
            <form onSubmit={handleCargaManual} style={styles.form}>
              <div style={styles.inputRow}>
                <input style={styles.inputS} placeholder="Tipo" onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required />
                <input style={styles.inputS} placeholder="Marca" onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required />
              </div>
              <div style={styles.inputRow}>
                <input style={styles.inputS} placeholder="Contenido" onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required />
                <input style={styles.inputS} type="number" placeholder="Peso Kg" onChange={e => setNuevoProd({...nuevoProd, peso: e.target.value})} required />
              </div>
              <input style={styles.inputS} type="number" placeholder="Precio" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required />
              <button type="submit" style={styles.btnSave}>Crear Borrador</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'Inter, sans-serif' },
  topBar: { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' },
  badgeLocal: { background: '#f1f5f9', padding: '5px 15px', borderRadius: '20px', fontSize: '0.8rem' },
  header: { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' },
  title: { fontSize: '1.8rem', fontWeight: '800' },
  btnPlus: { background: '#0f172a', color: '#fff', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' },
  btnBack: { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' },
  searchBox: { position: 'relative', display: 'flex', alignItems: 'center', gap: '10px', background: '#fff', padding: '10px 15px', borderRadius: '12px', border: '1px solid #e2e8f0', marginBottom: '25px' },
  searchInput: { border: 'none', outline: 'none', width: '100%' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' },
  card: { background: '#fff', padding: '20px', borderRadius: '15px', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' },
  cardHeader: { display: 'flex', justifyContent: 'space-between', marginBottom: '10px' },
  statusPub: { background: '#d1fae5', color: '#065f46', fontSize: '0.6rem', padding: '2px 6px', borderRadius: '4px', fontWeight: 'bold' },
  statusDraft: { background: '#f1f5f9', color: '#64748b', fontSize: '0.6rem', padding: '2px 6px', borderRadius: '4px', fontWeight: 'bold' },
  prodName: { margin: '0 0 10px 0', fontSize: '1rem' },
  priceRow: { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' },
  price: { fontWeight: 'bold', fontSize: '1.2rem' },
  stock: { fontSize: '0.8rem', color: '#64748b' },
  footer: { display: 'flex', gap: '10px', borderTop: '1px solid #f1f5f9', paddingTop: '15px' },
  btnEdit: { flex: 1, background: '#fff', border: '1px solid #e2e8f0', padding: '6px', borderRadius: '6px', cursor: 'pointer', fontSize: '0.8rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' },
  btnDel: { background: '#fee2e2', color: '#ef4444', border: 'none', padding: '6px 10px', borderRadius: '6px', cursor: 'pointer' },
  modalOverlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 },
  modalContent: { background: '#fff', padding: '30px', borderRadius: '20px', width: '400px' },
  modalHeader: { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' },
  form: { display: 'flex', flexDirection: 'column', gap: '15px' },
  inputRow: { display: 'flex', gap: '10px' },
  inputS: { padding: '10px', borderRadius: '8px', border: '1px solid #e2e8f0' },
  btnSave: { background: '#0284c7', color: '#fff', border: 'none', padding: '12px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' }
};

export default GestionOfertas;
